import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import CaseRow from "../../components/cases/CaseRow.js";
import "../dashboard/Dashboard.css";
import api from "../../api.js";
import { Plus, Search, Filter } from "lucide-react";

export default function CasesPage() {
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem("user"));
  const isAdmin = user?.role_id === 1;
  const [allCases, setAllCases] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("All");
  const [priorityFilter, setPriorityFilter] = useState("All");

  const getPriorityLabel = (num) => {
    switch (num) { case 3: return "High"; case 2: return "Medium"; case 1: return "Low"; default: return "Unknown"; }
  };

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await api.get("/cases");
        const data = res.data.message === "no assigned cases" ? [] : res.data;
        setAllCases(data);
        setFiltered(data);
      } catch (err) {
        console.error("Error fetching cases:", err);
        localStorage.removeItem("token");
        localStorage.removeItem("user");
        navigate("/", { replace: true });
      }
    };
    fetchData();
  }, [navigate]);

  useEffect(() => {
    let result = allCases;
    if (search) result = result.filter((c) => c.title?.toLowerCase().includes(search.toLowerCase()) || String(c.caseId).includes(search));
    if (statusFilter !== "All") result = result.filter((c) => c.status === statusFilter);
    if (priorityFilter !== "All") result = result.filter((c) => getPriorityLabel(c.priority) === priorityFilter);
    setFiltered(result);
  }, [search, statusFilter, priorityFilter, allCases]);

  const statusCounts = { All: allCases.length, Open: allCases.filter((c) => c.status === "Open").length, Close: allCases.filter((c) => c.status === "Close").length, Archived: allCases.filter((c) => c.status === "Archived").length };

  return (
    <div className="dashboardMain">
      <header className="dashboardHeader">
        <div className="headerBranding">
          <h1 className="logoText"><span>LEGALLENS</span> Cases</h1>
          <p className="systemStatus">
            {isAdmin ? "All cases in the system" : "Your assigned cases"} •{" "}
            <span className="highlightText">{allCases.length} total</span>
          </p>
        </div>
        {isAdmin && (
          <button className="primaryActionBtn" style={{ width: "auto", padding: "0.75rem 1.5rem" }} onClick={() => navigate("/create-case")}>
            <Plus size={16} /> Create Case
          </button>
        )}
      </header>

      {/* Status Filter Tabs */}
      <div className="notifFilterTabs" style={{ marginBottom: "1.5rem" }}>
        {Object.entries(statusCounts).map(([status, count]) => (
          <button
            key={status}
            className={`notifFilterTab ${statusFilter === status ? "notifFilterTabActive" : ""}`}
            onClick={() => setStatusFilter(status)}
          >
            {status} ({count})
          </button>
        ))}
      </div>

      {/* Search + Filter Row */}
      <div style={{ display: "flex", gap: "1rem", marginBottom: "1.5rem", alignItems: "center" }}>
        <div className="membersSearch" style={{ flex: 1, maxWidth: 400 }}>
          <Search size={16} color="#475569" />
          <input
            type="text"
            placeholder="Search by title or case ID..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={{ background: "transparent", border: "none", outline: "none", color: "#fff", fontSize: "0.875rem", flex: 1 }}
          />
        </div>
        <select
          value={priorityFilter}
          onChange={(e) => setPriorityFilter(e.target.value)}
          style={{ background: "#1e293b", border: "1px solid rgba(255,255,255,0.05)", color: "#fff", padding: "0.6rem 1rem", borderRadius: 8, fontSize: "0.875rem" }}
        >
          <option value="All">All Priorities</option>
          <option value="High">High</option>
          <option value="Medium">Medium</option>
          <option value="Low">Low</option>
        </select>
      </div>

      {/* Cases List */}
      <div className="formSectionCard">
        <div className="sectionHeader">
          <div className="indicatorDot" />
          <h2>CASE RECORDS</h2>
          <span style={{ marginLeft: "auto", color: "#64748b", fontSize: "0.8rem" }}>{filtered.length} result{filtered.length !== 1 ? "s" : ""}</span>
        </div>
        <div className="casesListWrapper" style={{ padding: "0.5rem 0" }}>
          {filtered.length === 0 ? (
            <div style={{ textAlign: "center", padding: "3rem", color: "#475569" }}>
              <p>No cases found</p>
              {isAdmin && <button className="primaryActionBtn" style={{ width: "auto", marginTop: "1rem" }} onClick={() => navigate("/create-case")}><Plus size={16} /> Create First Case</button>}
            </div>
          ) : (
            filtered.map((c) => (
              <CaseRow key={c.id} id={c.caseId} title={c.title} priority={getPriorityLabel(c.priority)} status={c.status} />
            ))
          )}
        </div>
      </div>
    </div>
  );
}
